const msg = item.message || item.user_request || '';
if (!msg.trim()) {
  return [{ json: { error: true, error_type: 'VALIDATION_FAILED', message: 'Missing required field: message', request_id: item.request_id || ('req_' + Date.now()), timestamp: new Date().toISOString() } }];
}
return [{ json: {
  request_id: item.request_id || ('req_' + Date.now()),
  user_id: item.user_id || 'anonymous',
  message: msg,
  context: item.context || {},
  preferences: item.preferences || {},
  is_valid: true,
  timestamp: new Date().toISOString()
} }];

const item=$input.first().json;
if(item.error){return [{json:item}];}
var body={model:'claude-sonnet-4-6',max_tokens:256,messages:[{role:'user',content:'Classify this request into exactly one task_type. Return ONLY JSON: {"task_type":"<type>","rationale":"<1 sentence>"}\nTypes: discovery|system_design|implementation_planning|full_product_flow|default\nREQUEST: '+item.message+'\nCONTEXT: '+JSON.stringify(item.context||{})}]};
return [{json:{...item,apiBody:body}}];

const item=$input.first().json;
var rawText='';
try{
  if(item.content&&Array.isArray(item.content)){rawText=item.content[0].text||'';}
  else if(typeof item.content==='string'){rawText=item.content;}
}catch(e){}
var cls={task_type:'default',rationale:''};
try{var m=rawText.match(/\{[\s\S]*\}/);if(m)cls=JSON.parse(m[0]);}catch(e){}
var now=new Date().toISOString();
return [{json:{
  request_id:item.request_id,
  task_type:cls.task_type||'default',
  user_request:item.message,
  context:item.context||{},
  constraints:item.preferences||{},
  upstream_outputs:{},
  metadata:{timestamp:now,workflow_name:'AG_00_ENTRYPOINT_SUPERVISOR',persona_name:'SUPERVISOR'},
  classification_rationale:cls.rationale||'',
  user_id:item.user_id||'anonymous'
}}];

